import base64
import hashlib

def obfuscate_data(data):
    # Use base64 encoding to obfuscate data
    encoded_data = base64.b64encode(data)
    return encoded_data

def deobfuscate_data(encoded_data):
    # Use base64 decoding to deobfuscate data
    decoded_data = base64.b64decode(encoded_data)
    return decoded_data

