**Access Control Module:**
```java
import java.util.HashMap;
import java.util.Map;

public class AccessControl {
    private Map<String, String> accessControlList;

    public AccessControl() {
        accessControlList = new HashMap<>();
        accessControlList.put("admin", "read,write,execute");
        accessControlList.put("user", "read,execute");
    }

    public boolean checkAccess(String user, String action) {
        // Check if the user has the required access level
        String accessLevel = accessControlList.get(user);
        if (accessLevel != null) {
            String[] actions = accessLevel.split(",");
            for (String actionRequired : actions) {
                if (actionRequired.equals(action)) {
                    return true;
                }
            }
        }
        return false;
    }

    public static void main(String[] args) {
        AccessControl accessControl = new AccessControl();
        System.out.println(accessControl.checkAccess("admin", "read")); // true
        System.out.println(accessControl.checkAccess("user", "write")); // false
    }
}
```

